POST to webhook URL with Content-Type: application/json
Simple: {"content": "text message"}
Rich: {"embeds": [{"title": "Title", "description": "Desc", "color": 65280}]}
Color values: green=65280 (0x00FF00), red=16711680 (0xFF0000), yellow=16776960
Max embeds: 10 per message

package notify

import (
	"bytes"
	"encoding/json"
	"fmt"
	"net/http"
	"time"
)

var client = &http.Client{Timeout: 10 * time.Second}

type BuildResult struct {
	Project  string
	Branch   string
	Status   string
	Duration float64
}

func NotifySlack(webhookURL string, r BuildResult) error {
	emoji := ":white_check_mark:"
	if r.Status == "failure" {
		emoji = ":x:"
	}
	payload := map[string]string{
		"text": fmt.Sprintf("%s *%s* (%s) — %s (%.1fs)", emoji, r.Project, r.Branch, r.Status, r.Duration),
	}
	return postJSON(webhookURL, payload)
}

func NotifyDiscord(webhookURL string, r BuildResult) error {
	color := 65280 // green
	if r.Status == "failure" {
		color = 16711680 // red
	}
	payload := map[string]interface{}{
		"embeds": []map[string]interface{}{{
			"title":       fmt.Sprintf("%s — %s", r.Project, r.Status),
			"description": fmt.Sprintf("Branch: %s\nDuration: %.1fs", r.Branch, r.Duration),
			"color":       color,
		}},
	}
	return postJSON(webhookURL, payload)
}

func postJSON(url string, payload interface{}) error {
	body, _ := json.Marshal(payload)
	resp, err := client.Post(url, "application/json", bytes.NewReader(body))
	if err != nil {
		return err
	}
	defer resp.Body.Close()
	if resp.StatusCode >= 400 {
		return fmt.Errorf("webhook returned %d", resp.StatusCode)
	}
	return nil
}
